const items = $input.all();
const busqueda = ($('Ejecutar Workflow').first().json.busqueda ?? '').trim();

// Detect empty result
const rows = (items.length === 1 && !items[0].json.property_id) ? [] : items;

if (rows.length === 0) {
  return [{ json: { resultado: `🔍 No se encontraron inmuebles ni clientes interesados en "${busqueda}".` } }];
}

// Group by property_id
const propMap = {};
rows.forEach(it => {
  const r = it.json;
  const pid = r.property_id;
  if (!propMap[pid]) {
    propMap[pid] = {
      code: r.property_code,
      address: r.property_address,
      status: r.property_status,
      type: r.property_type,
      zone: r.zone,
      land_area: r.land_area,
      construction_area: r.construction_area,
      price: r.price,
      confirmed: {},   // client_id → {name, phone, email, registrations[], notes[]}
      potential: {}    // client_id → {name, phone, email, interest_description}
    };
  }
  const r2 = it.json;
  const cid = r2.client_id;
  if (r2.match_type === 'confirmado') {
    if (!propMap[pid].confirmed[cid]) {
      propMap[pid].confirmed[cid] = { name: r2.client_name, phone: r2.phone, email: r2.email, registrations: [], notes: [] };
    }
    propMap[pid].confirmed[cid].registrations.push({ level: r2.interest_level, date: r2.interest_date });
    if (r2.notes) propMap[pid].confirmed[cid].notes.push(r2.notes);
  } else {
    propMap[pid].potential[cid] = {
      name: r2.client_name,
      phone: r2.phone,
      email: r2.email,
      interest_description: r2.interest_description
    };
  }
});

const levelRank = { 'Muy Alto': 4, 'Alto': 3, 'Medio': 2, 'Bajo': 1 };
const levelEmoji = { 'Muy Alto': '🔥', 'Alto': '⬆️', 'Medio': '➡️', 'Bajo': '⬇️' };
const props = Object.values(propMap);

// Multi-property disambiguation
if (props.length > 1) {
  const lista = props.map((p, i) => {
    const nc = Object.keys(p.confirmed).length;
    const np = Object.keys(p.potential).length;
    return `${i + 1}. *${p.code}* - ${p.address} (${nc} confirmado(s), ${np} potencial(es))`;
  }).join('\n');
  return [{ json: { resultado: `🏠 Encontré ${props.length} inmuebles en "${busqueda}":\n\n${lista}\n\n👉 Indícame el código exacto para ver el detalle de sus interesados.` } }];
}

// Single property
const prop = props[0];
const confirmedList = Object.values(prop.confirmed);
const potentialList = Object.values(prop.potential);

const priceStr = prop.price > 0 ? `$${Number(prop.price).toLocaleString('es-EC')}` : 'Precio no definido';
const areaStr = prop.land_area > 0 ? `${prop.land_area}m² terreno` : '';
const constStr = prop.construction_area > 0 ? `${prop.construction_area}m² construcción` : '';

const lines = [
  `👥 *Interesados — Inmueble ${prop.code}*`,
  `📍 ${prop.address} | ${prop.type} | ${prop.zone} | ${prop.status}`,
  areaStr || constStr ? `📐 ${[areaStr, constStr].filter(Boolean).join(' | ')}` : null,
  `💰 ${priceStr}`,
  ''
].filter(l => l !== null);

// ── Section 1: Confirmed ──────────────────────────────────────────────────────
if (confirmedList.length > 0) {
  // Sort by highest interest level
  confirmedList.sort((a, b) => {
    const maxA = Math.max(...a.registrations.map(r => levelRank[r.level] || 0));
    const maxB = Math.max(...b.registrations.map(r => levelRank[r.level] || 0));
    return maxB - maxA || b.registrations.length - a.registrations.length;
  });

  lines.push(`✅ *Interesados confirmados (${confirmedList.length}):*`);
  confirmedList.forEach((c, i) => {
    const maxLevel = c.registrations.reduce((best, r) =>
      (levelRank[r.level] || 0) > (levelRank[best] || 0) ? r.level : best, 'Bajo');
    const emoji = levelEmoji[maxLevel] || '•';
    const count = c.registrations.length;
    const countLabel = count > 1 ? ` _(registrado ${count}x — interés elevado)_` : '';
    lines.push(`${i + 1}. ${emoji} *${c.name}*${countLabel}`);
    lines.push(`   📞 ${c.phone}${c.email ? ' | ✉️ ' + c.email : ''}`);
    lines.push(`   Nivel: ${maxLevel}`);
    const uniqueNotes = [...new Set(c.notes.filter(Boolean))];
    if (uniqueNotes.length) lines.push(`   💬 ${uniqueNotes.join(' | ')}`);
    lines.push('');
  });
} else {
  lines.push(`✅ *Interesados confirmados:* Ninguno registrado aún.`);
  lines.push('');
}

// ── Section 2: Potential ──────────────────────────────────────────────────────
if (potentialList.length > 0) {
  lines.push(`🔍 *Clientes potencialmente interesados (${potentialList.length}):*`);
  lines.push(`_(Basado en su descripción de búsqueda — no vinculados aún)_`);
  lines.push('');
  potentialList.forEach((c, i) => {
    lines.push(`${i + 1}. 💡 *${c.name}*`);
    lines.push(`   📞 ${c.phone}${c.email ? ' | ✉️ ' + c.email : ''}`);
    lines.push(`   🔎 Busca: _"${c.interest_description}"_`);
    lines.push('');
  });
  lines.push(`💡 ¿Deseas vincular alguno de estos clientes como interesado en este inmueble?`);
} else {
  lines.push(`🔍 *Clientes potenciales:* No se encontraron clientes con búsquedas compatibles.`);
}

return [{ json: { resultado: lines.join('\n') } }];
